use Talabat
create table Drivers (
driver_id int IDENTITY(1,1) ,
current_status varchar(50) not null ,
vechile_type varchar(50) default 'halawa' ,
license_plate varchar(50) default 0 ,
primary key (driver_id) 
);
create table Menu_items(
item_id int identity(1,1) primary key,
base_price decimal(10,2) default 0 ,
name varchar(50) not null,
description varchar(50) 
);
create table Customers (
customer_id int identity(1,1) primary key,
name varchar(50) not null ,
e_mail varchar(50) unique ,
password varchar(50) unique ,
role varchar(50) default 'browser',
driver_id int ,
FOREIGN KEY(driver_id) REFERENCES Drivers (driver_id) 
) ;
create table Restaurants (
    res_id int identity(1,1) primary key,
    name varchar(50) not null,
    cont_date date, 
    logo varchar(255) 
);
create table Branches (
    bran_id int identity(1,1) primary key,
    location varchar(100),
    is_active VARCHAR(50) default 1,
    res_id int,
    foreign key (res_id) references Restaurants (res_id)
);
create table Addresses (
    add_id int identity(1,1) primary key,
    floor int,
    city varchar(50),
    street varchar(50),
    building_no int,
    gps_location varchar(100),
    cus_id int,
    foreign key (cus_id) references Customers (customer_id)
);
create table Orders (
    order_id int identity(1,1) primary key,
    status varchar(50) default 'pending',
    created_at datetime default getdate(),
    delivery_fee decimal(10,2) default 0,
    customer_id int,
    del_id int, 
    res_id int, 
    foreign key (customer_id) references Customers (customer_id),
    foreign key (del_id) references Drivers (driver_id),
    foreign key (res_id) references Restaurants (res_id)
);
create table Order_Details (
    order_detail_id int identity(1,1) primary key,
    unit_price decimal(10,2),
    quantity int not null,
    order_id int,
    item_id int,
    foreign key (order_id) references Orders (order_id),
    foreign key (item_id) references Menu_items (item_id)
);
create table Coupons (
    cop_id int identity(1,1) primary key,
    value decimal(10,2),
    exp_date date,
    code varchar(20) unique,
    discount_type varchar(20),
    order_id int,
    foreign key (order_id) references Orders (order_id)
);
create table Categories (
    cat_id int identity(1,1) primary key,
    name varchar(50) not null
);
create table Items_Cat (
    cat_id int,
    item_id int,
    primary key (cat_id, item_id),
    foreign key (cat_id) references Categories (cat_id),
    foreign key (item_id) references Menu_items (item_id)
);
create table Customer_Phones (
    cus_id int,
    phone varchar(15),
    primary key (cus_id, phone),
    foreign key (cus_id) references Customers (customer_id)
);










