--views

CREATE OR ALTER VIEW Detailed_Orders_ AS
SELECT 
    o.order_id,
    c.name AS Customer_Name,
    o.status AS Order_Status,
    (SELECT SUM(unit_price * quantity) FROM Order_Details WHERE order_id = o.order_id) AS Computed_Total,
    d.driver_id AS Driver_ID,
    r.name AS Restaurant_Name,
    o.created_at
FROM Orders o
LEFT JOIN Customers c ON o.customer_id = c.customer_id
LEFT JOIN Drivers d ON o.del_id = d.driver_id
LEFT JOIN Restaurants r ON o.res_id = r.res_id;




